-- V9: Add code column, rename name to display_name, seed system categories from Plaid PFCv2.

-- Schema changes
ALTER TABLE categories RENAME COLUMN name TO display_name;
ALTER TABLE categories ADD COLUMN code VARCHAR(64);

-- System categories must have a code; user categories may not.
ALTER TABLE categories ADD CONSTRAINT categories_system_has_code
    CHECK ((user_id IS NULL AND code IS NOT NULL) OR (user_id IS NOT NULL AND code IS NULL));

-- Codes are unique among system categories.
CREATE UNIQUE INDEX categories_code_system_unique
    ON categories(code) WHERE user_id IS NULL;

-- Seed primary categories (16 rows). Plaid PFCv2 primaries.

